<template>  <div>    <header>      <div class="primary-color rounded-xl shadow-lg p-2">        <h1 class="text-center" style="font-family: 'Arial'">          {{ t('titles.invoiceList') }}        </h1>      </div>    </header>    <main class="grid gap-6 my-10">      <!-- Search bar -->      <div class="flex secondary-color rounded-xl shadow-lg p-4 gap-3 w-full justify-between">        <UInput            icon="i-heroicons-magnifying-glass-20-solid"            size="xl"            v-model="searchQueryPending"            type="text"            :placeholder="t('misc.search') + '...'"            class="w-full"            @keyup.enter="runSearch"        />        <UButton            icon="i-heroicons-magnifying-glass-circle"            size="xl"            @click="runSearch"        />      </div>      <!-- Table -->      <div class="secondary-color rounded-xl shadow-lg p-4 w-full">        <div class="flex justify-end">          <UButton              variant="button"              class="rounded-xl"              :to="{ path: '/invoices/new', query: { callback: route.fullPath } }"              icon="gg:add"          >            {{ t('titles.newInvoice') }}          </UButton>        </div>        <div v-if="isLoading" class="grid gap-4 mt-4">          <p>Loading...</p>        </div>        <div v-else class="grid gap-2 mt-4">          <UTable            ref="table"            :data="pagedEventsWithInvoices"            :columns="columns"            :loading="isLoading"            :get-sub-rows="row => row.children"            class="rounded-md"            :ui="{ td: 'empty:p-0' }"            @select="onSelectInvoice"          />          <!-- Pagination footer -->          <div class="flex justify-center pt-4">            <UPagination              :page="pagination.pageIndex + 1"              :items-per-page="pagination.pageSize"              :total="filteredEventsWithInvoices.length"              @update:page="onPageChange"            />          </div>        </div>      </div>    </main>  </div></template><script setup lang="ts">import { ref, onMounted, computed, resolveComponent, h, watch } from 'vue'import { useAuth } from '#imports'import type { TableColumn, TableRow } from '@nuxt/ui'definePageMeta({  middleware: 'auth-admin'})const { t } = useI18n()const { public: { apiBase } } = useRuntimeConfig()const route = useRoute()const router = useRouter()const toast = useToast()const isLoading = ref(false)const searchQueryPending = ref(route.query.q ? String(route.query.q) : '')const searchQuery = ref<string>(route.query.q ? String(route.query.q) : '')function onSelectInvoice(row: TableRow<InvoiceTableRow>) {  if (row.original.isItem){    return  }  row.toggleExpanded()}type Contact = {  id: number  companyName: string  companyCity: string  companyCountry: string  companyAddress: string  companyNumber: string  companyVatNumber: string}type PaymentStatus = 'Paid' | 'Unpaid'const getColorByStatus = (status: PaymentStatus) => {  return {    Paid: 'success',    Unpaid: 'error'  }[status]}type InvoiceItem = {  id: number  service: string  measure: string  pieces: number  cost: number  totalCost: number}type Invoice = {  id: number  invoiceNumber: number  date: string  invoiceStatus: PaymentStatus | string  invoiceItemList?: InvoiceItem[]  invoiceItem?: InvoiceItem[] | null  contactsBook: Contact | null  totalCost?: number}type Event = {  id: number  title: string  address: string  date: string  invoiceList?: Invoice[]}type InvoiceTableRow = {  id: number | string  isEvent: boolean  isInvoice?: boolean  isItem?: boolean  title?: string  eventId?: number  invoiceNumber?: number  invoiceStatus?: PaymentStatus | string  date?: string  companyName?: string  service?: string  measure?: string  pieces?: number  cost?: number  amount?: number  children?: InvoiceTableRow[]}const eventList = ref<Event[]>([])const pagination = ref({  pageIndex: route.query.page ? Math.max(Number(route.query.page) - 1, 0) : 0,  pageSize: 5})const UButton = resolveComponent('UButton')const UBadge = resolveComponent('UBadge')const columns: TableColumn<InvoiceTableRow>[] = [  {    accessorKey: 'id',    header: t('invoices.event') + " / " + t('invoices.invoice'),    cell: ({ row }) => {      const r = row.original      const isEvent = r.isEvent      const isInvoice = r.isInvoice      const isItem = r.isItem      if (isEvent) {        return h(            'div',            {              style: { paddingLeft: `${row.depth}rem` },              class: 'flex items-center gap-2 font-bold'            },            [              h(UButton as any, {                color: 'neutral',                variant: 'outline',                size: 'xs',                icon: row.getIsExpanded() ? 'i-lucide-minus' : 'i-lucide-plus',                class: !row.getCanExpand() && 'invisible',                ui: {                  base: 'p-0 rounded-sm',                  leadingIcon: 'size-4'                },                onClick: row.getToggleExpandedHandler()              }),              h('span', null, String(r.title))            ]        )      }      if (isInvoice) {        return h(            'div',            {              style: { paddingLeft: `${row.depth}rem` },              class: 'flex items-center gap-2'            },            [              h(UButton as any, {                color: 'neutral',                variant: 'outline',                size: 'xs',                icon: row.getIsExpanded() ? 'i-lucide-minus' : 'i-lucide-plus',                class: !row.getCanExpand() && 'invisible',                ui: {                  base: 'p-0 rounded-sm',                  leadingIcon: 'size-4'                },                onClick: row.getToggleExpandedHandler()              }),              h('span', null, `#${r.invoiceNumber}`)            ]        )      }      if (isItem) {        const label = `${r.service ?? ''}`        return h(            'div',            {              style: { paddingLeft: `${row.depth + 1}rem` },              class: 'text-sm'            },            label        )      }      return h('span', null, String(r.id))    }  },  {    accessorKey: 'date',    header: t('invoices.date'),    cell: ({ row }) => {      const r = row.original      if (r.isEvent) return h('p', null, r.date)      if (r.isInvoice) return h('p', null, r.date)      if (r.isItem) return h('p', null, "—")      return h('p', null, '')    }  },  {    accessorKey: 'invoiceStatus',    header: t('invoices.status'),    cell: ({ row }) => {      const r = row.original      if (r.isEvent) return h('span', null, '—')      if (r.isItem) {        const label = `${r.pieces != null ? `${r.pieces} ${r.measure ?? ''}` : ''        }`        return h(            'div',            {              style: {},              class: ''            },            label        )      }      if (r.isInvoice) {        const status = (r.invoiceStatus || 'Unpaid') as PaymentStatus        return h(            UBadge as any,            {              color: getColorByStatus(status),              variant: 'solid',              class: 'capitalize'            },            () => status        )      }    }  },  {    accessorKey: 'companyName',    header: t('invoices.companyName'),    cell: ({ row }) => {      const r = row.original      if (r.isEvent) return h('span', null, '—')      if (r.isItem) {        const raw = r.cost        const amount = raw != null ? Number(raw) : null        if (amount == null || Number.isNaN(amount)) return h('div', {}, '')        const formatted = new Intl.NumberFormat('lt-LT', {          style: 'currency',          currency: 'EUR'        }).format(amount)        const label = `${r.cost != null ? `${formatted}` : ''        }`        return h(            'div',            {              style: {},              class: ''            },            label        )      }      if (r.isInvoice) {        return h('p', null, r.companyName || '—')      }      return h('p', null, '')    }  },  {    accessorKey: 'amount',    header: t('invoices.total'),    cell: ({ row }) => {      const r = row.original      const amount = r.amount      if (amount === undefined || amount === null) {        return h('div', {}, r.isEvent || r.isInvoice ? '—' : '')      }      const formatted = new Intl.NumberFormat('lt-LT', {        style: 'currency',        currency: 'EUR'      }).format(amount)      let cls = ''      if (r.isEvent) cls = 'font-bold'      else if (r.isInvoice) cls = ''      else if (r.isItem) cls = 'text-sm'      return h('div', { class: cls }, formatted)    }  },  {    accessorKey: 'actions',    header: '',    cell: ({ row }) => {      const r = row.original      if (r.isInvoice){        return h('div', { class: 'flex justify-end gap-2' }, [          h(UButton, {            icon: 'i-heroicons-pencil-square',            to: {              path: `/invoices/${r.id}`,              query: {callback: route.fullPath}            },            class: 'hover:scale-[110%] border-1',            onClick: (e: MouseEvent) => e.stopPropagation()          }),          h(UButton, {            icon: 'mynaui:trash',            class: 'hover:scale-[110%] border-1',            onClick: () => deleteInvoice(Number(r.id))          })        ])      }      return h('p', null, '')    }  }]async function deleteInvoice(invoiceId: number) {  const confirmDelete = confirm("Are you sure you want to delete this invoice?");  if (!confirmDelete) return;  try {    const deleteResponse = await fetch(`${apiBase}/admin/invoices/${invoiceId}`, {      method: 'DELETE',      headers: {        'Authorization': `Bearer ${userToken}`      }    });    if (!deleteResponse.ok) {      throw new Error('Failed to delete invoice!');    }    toast.add({      title: t('alerts.success'),      description: t('alerts.invoiceDeleted'),      icon: 'qlementine-icons:success-12'    })    findEvents()  } catch (error) {    console.error('Error deleting invoice:', error);  }}const { data } = useAuth()const userToken = (data?.value?.user as any)?.tokenasync function findEvents() {  isLoading.value = true  try {    const response = await fetch(`${apiBase}/admin/events`, {      method: 'GET',      headers: {        Authorization: `Bearer ${userToken}`      }    })    if (!response.ok) {      throw new Error('Failed to fetch events!')    }    const json = await response.json()    eventList.value = json as Event[]  } catch (error: any) {    console.error(error)    alert(error.message || 'Failed to fetch events!')  } finally {    isLoading.value = false  }}const eventsWithInvoices = computed<InvoiceTableRow[]>(() => {  return eventList.value      .map((ev) => {        const invoices: Invoice[] =            (ev as any).invoiceList || (ev as any).invoices || []        const invoiceRows: InvoiceTableRow[] = invoices.map((inv) => {          const items: InvoiceItem[] =              (inv as any).invoiceItemList ||              (inv as any).invoiceItem ||              []          const itemRows: InvoiceTableRow[] = items.map((item) => {            const lineTotal =                item.totalCost ??                (item.cost != null && item.pieces != null                    ? Number(item.cost) * Number(item.pieces)                    : 0)            return {              id: `item-${inv.id}-${item.id}`,              isEvent: false,              isInvoice: false,              isItem: true,              service: item.service,              measure: item.measure,              pieces: item.pieces,              cost: item.cost,              amount: lineTotal            }          })          const invoiceTotal =              itemRows.reduce((sum, r) => sum + (r.amount || 0), 0) ||              (inv.totalCost != null ? Number(inv.totalCost) : 0)          return {            id: inv.id,            isEvent: false,            isInvoice: true,            isItem: false,            invoiceNumber: inv.invoiceNumber,            date: inv.date,            invoiceStatus: inv.invoiceStatus,            companyName: inv.contactsBook?.companyName ?? '',            amount: invoiceTotal,            children: itemRows          } as InvoiceTableRow        })        const eventTotal = invoiceRows.reduce(            (sum, invRow) => sum + (invRow.amount || 0),            0        )        return {          id: ev.id,          isEvent: true,          isInvoice: false,          isItem: false,          eventId: ev.id,          title: ev.title,          date: ev.date,          amount: eventTotal,          children: invoiceRows        } as InvoiceTableRow      })      .filter((row) => row.children && row.children.length > 0)})const filteredEventsWithInvoices = computed<InvoiceTableRow[]>(() => {  const q = searchQuery.value.trim().toLowerCase()  if (!q) return eventsWithInvoices.value  return eventsWithInvoices.value.filter((ev) =>      (ev.title || '').toLowerCase().includes(q)  )})const pagedEventsWithInvoices = computed<InvoiceTableRow[]>(() => {  const start = pagination.value.pageIndex * pagination.value.pageSize  const end = start + pagination.value.pageSize  return filteredEventsWithInvoices.value.slice(start, end)})function runSearch() {  const q = searchQueryPending.value.trim()  searchQuery.value = q  pagination.value.pageIndex = 0}function onPageChange(p: number) {  pagination.value.pageIndex = p - 1}watch(    () => route.query,    (query) => {      const q = query.q ? String(query.q) : ''      if (q !== searchQuery.value) {        searchQuery.value = q        searchQueryPending.value = q        pagination.value.pageIndex = 0      }      const page = query.page ? Math.max(Number(query.page) - 1, 0) : 0      if (page !== pagination.value.pageIndex) {        pagination.value.pageIndex = page      }    },    { immediate: true })watch(    [searchQuery, () => pagination.value.pageIndex],    ([q, pageIndex]) => {      router.replace({        query: {          q: q || undefined,          page: pageIndex > 0 ? String(pageIndex + 1) : undefined        }      })    })onMounted(() => {  findEvents()})</script>